document.addEventListener("DOMContentLoaded",()=>{const e=new URLSearchParams(location.search),t=(e.get("id")||e.get("artist")||"").toLowerCase(),o=document.querySelectorAll(".shop-item");if(!t)return;o.forEach(e=>{const o=(e.dataset.artist||"").toLowerCase();e.style.display=o===t?"":"none"});const r=document.querySelector("h2");r&&(r.textContent=`${t.toUpperCase()} artworks`)});